parameters.jsCode:
const items = $input.all();
const videos = items.map(i => i.json).flat();
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);

const videoUrls = videos
  .filter(v => {
    const d = v.uploadDate || v.date || v.publishedAt || '';
    if (!d) return true;
    return new Date(d).getTime() >= thirtyDaysAgo;
  })
  .map(v => v.url || v.videoUrl || (v.id ? `https://www.youtube.com/watch?v=${v.id}` : ''))
  .filter(url => url && url.includes('youtube.com'))
  .slice(0, 5);

return [{ json: {
  businessId: $('Prepare Business Data1').item.json.id,
  businessName: $('Prepare Business Data1').item.json.name,
  placeid: $('Prepare Business Data1').item.json.placeid,
  facebookurl: $('Prepare Business Data1').item.json.facebookurl,
  instagramurl: $('Prepare Business Data1').item.json.instagramurl,
  youtubeurl: $('Prepare Business Data1').item.json.youtubeurl,
  ytVideoUrls: videoUrls,
  hasYtVideos: videoUrls.length > 0
}}];

const items = $input.all();
const posts = items.map(i => i.json).flat();
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);

const postUrls = posts
  .filter(p => {
    const d = p.timestamp || p.takenAtTimestamp || p.date || '';
    if (!d) return true;
    const ts = typeof d === 'number' ? d * 1000 : new Date(d).getTime();
    return ts >= thirtyDaysAgo;
  })
  .map(p => p.url || p.displayUrl || p.shortCode ? `https://www.instagram.com/p/${p.shortCode}/` : '')
  .filter(url => url && url.includes('instagram.com'))
  .slice(0, 5);

return [{ json: {
  businessId: $('Prepare Business Data1').item.json.id,
  businessName: $('Prepare Business Data1').item.json.name,
  placeid: $('Prepare Business Data1').item.json.placeid,
  facebookurl: $('Prepare Business Data1').item.json.facebookurl,
  instagramurl: $('Prepare Business Data1').item.json.instagramurl,
  youtubeurl: $('Prepare Business Data1').item.json.youtubeurl,
  igPostUrls: postUrls,
  hasIgPosts: postUrls.length > 0
}}];

const items = $input.all();
const posts = items.map(i => i.json).flat();
const thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);

const postUrls = posts
  .filter(p => {
    const d = p.time || p.timestamp || p.date || p.createdAt || '';
    if (!d) return true;
    const ts = typeof d === 'number' ? d * 1000 : new Date(d).getTime();
    return ts >= thirtyDaysAgo;
  })
  .map(p => p.url || p.postUrl || p.link || '')
  .filter(url => url && url.includes('facebook.com'))
  .slice(0, 5); // max 5 posts to save credits

return [{ json: {
  businessId: $('Prepare Business Data1').item.json.id,
  businessName: $('Prepare Business Data1').item.json.name,
  placeid: $('Prepare Business Data1').item.json.placeid,
  facebookurl: $('Prepare Business Data1').item.json.facebookurl,
  instagramurl: $('Prepare Business Data1').item.json.instagramurl,
  youtubeurl: $('Prepare Business Data1').item.json.youtubeurl,
  fbPostUrls: postUrls,
  hasFbPosts: postUrls.length > 0
}}];

const business = $input.first().json;
return [{ json: {
