parameters.text:
=Analyze the Facebook, Instagram, YouTube and Google Reviews comments for "{{ $json.businessName }}" from the last 30 days.

FACEBOOK COMMENTS ({{ $json.fbCommentCount }} total):
{{ $json.fbComments.map((c, i) => (i+1) + '. [' + c.author + ']: ' + c.text).join('\n') || 'No comments found.' }}

INSTAGRAM COMMENTS ({{ $json.igCommentCount }} total):
{{ $json.igComments.map((c, i) => (i+1) + '. [' + c.author + ']: ' + c.text).join('\n') || 'No comments found.' }}

YOUTUBE COMMENTS ({{ $json.ytCommentCount }} total):
{{ $json.ytComments.map((c, i) => (i+1) + '. [' + c.author + ']: ' + c.text).join('\n') || 'No comments found.' }}

GOOGLE REVIEWS ({{ $json.googleCommentCount }} total):
{{ $json.googleComments.map((c, i) => (i+1) + '. [' + c.author + ']: ' + c.text).join('\n') || 'No reviews found.' }}

Give four separate summaries — one per platform.

parameters.jsCode:
const all = $input.all();

const fbData  = all.find(i => i.json.platform === 'facebook') || { json: { comments: [], commentCount: 0 } };
const igData  = all.find(i => i.json.platform === 'instagram') || { json: { comments: [], commentCount: 0 } };
const ytData  = all.find(i => i.json.platform === 'youtube') || { json: { comments: [], commentCount: 0 } };
const gData   = all.find(i => i.json.platform === 'google') || { json: { comments: [], commentCount: 0, ratingOnlyCounts: {} } };

const business = fbData.json.businessId ? fbData.json
  : (igData.json.businessId ? igData.json
  : (ytData.json.businessId ? ytData.json : gData.json));

return [{ json: {
  businessId:       business.businessId || business.id,
  businessName:     business.businessName || business.name,
  facebookurl:      business.facebookurl  || '',
  instagramurl:     business.instagramurl || '',
  youtubeurl:       business.youtubeurl   || '',
  fbComments:       fbData.json.comments  || [],
  fbCommentCount:   fbData.json.commentCount || 0,
  igComments:       igData.json.comments  || [],
  igCommentCount:   igData.json.commentCount || 0,
  ytComments:       ytData.json.comments  || [],
  ytCommentCount:   ytData.json.commentCount || 0,
  googleComments:   gData.json.comments   || [],
  googleCommentCount: gData.json.commentCount || 0,
  googleRatingOnly: gData.json.ratingOnlyCounts || {}
}}];

const items = $input.all();
const business = $('Extract YT Video URLs1').item.json;
const allComments = items.map(i => Array.isArray(i.json) ? i.json : [i.json]).flat();

const comments = allComments
  .map(c => ({
    text: c.text || c.textDisplay || c.comment || '',
    date: c.publishedAt || c.date || '',
    likes: c.likeCount || c.likes || 0,
    author: c.authorDisplayName || c.username || 'Unknown'
  }))
  .filter(c => c.text && c.text.trim().length > 0)
  .slice(0, 80);

return [{ json: {
  platform: 'youtube',
  businessId: business.businessId,
  businessName: business.businessName,
  placeid: business.placeid,
  facebookurl: business.facebookurl,
  instagramurl: business.instagramurl,
  youtubeurl: business.youtubeurl,
  comments: comments,
  commentCount: comments.length
}}];

const items = $input.all();
const business = $('Extract IG Post URLs1').item.json;
const allComments = items.map(i => Array.isArray(i.json) ? i.json : [i.json]).flat();

const comments = allComments
  .map(c => ({
    text: c.text || c.comment || '',
    date: c.timestamp || c.date || c.createdAt || '',
    likes: c.likesCount || c.likes || 0,
    author: c.ownerUsername || c.username || 'Unknown'
  }))
  .filter(c => c.text && c.text.trim().length > 0)
  .slice(0, 80);

return [{ json: {
  platform: 'instagram',
  businessId: business.businessId,
  businessName: business.businessName,
  placeid: business.placeid,
  facebookurl: business.facebookurl,
  instagramurl: business.instagramurl,
  youtubeurl: business.youtubeurl,
  comments: comments,
  commentCount: comments.length
}}];

const items = $input.all();
const business = $('Extract FB Post URLs1').item.json;
const allComments = items.map(i => Array.isArray(i.json) ? i.json : [i.json]).flat();

const comments = allComments
  .map(c => ({
    text: c.text || c.comment || c.message || '',
    date: c.date || c.createdAt || c.timestamp || '',
    likes: c.likesCount || c.likes || 0,
    author: c.authorName || c.profileName || c.username || 'Unknown'
  }))
  .filter(c => c.text && c.text.trim().length > 0)
  .slice(0, 80);

return [{ json: {
  platform: 'facebook',
  businessId: business.businessId,
  businessName: business.businessName,
  placeid: business.placeid,
  facebookurl: business.facebookurl,
  instagramurl: business.instagramurl,
  youtubeurl: business.youtubeurl,
  comments: comments,
  commentCount: comments.length
}}];

const reviews = $input.all();
let business;
try { business = $('Prepare Business Data1').item.json; }
catch(e) { business = {}; }

const writtenReviews = [];
const ratingOnlyCounts = {};

reviews.forEach(item => {
  const review = item.json;
  const stars = review.stars || null;
  const text = review.text ? review.text.trim() : null;
  if (text) {
    writtenReviews.push({ text: `${stars} stars: "${text}"`, author: review.name || 'Unknown', date: review.publishedAtDate || '' });
  } else if (stars) {
    ratingOnlyCounts[stars] = (ratingOnlyCounts[stars] || 0) + 1;
  }
});

const comments = writtenReviews.map(r => ({
  text: r.text,
  author: r.author,
  date: r.date,
  likes: 0
})).slice(0, 80);

return [{ json: {
  platform: 'google',
  businessId: business.id,
  businessName: business.name,
  placeid: business.placeid,
  facebookurl: business.facebookurl,
  instagramurl: business.instagramurl,
  youtubeurl: business.youtubeurl,
  comments: comments,
  commentCount: comments.length,
  ratingOnlyCounts: ratingOnlyCounts
}}];
